import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';
import './BrowseWorkers.css';

const BrowseWorkers = () => {
  const [workers, setWorkers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [city, setCity] = useState('');
  const navigate = useNavigate();

  const categories = [
    { id: 'all', label: 'All Workers', skill: '' },
    { id: 'painter', label: 'Painters', icon: '­¤Ä©', skill: 'painter' },
    { id: 'electrician', label: 'Electricians', icon: 'ŌÜĪ', skill: 'electrician' },
    { id: 'mason', label: 'Masons', icon: '­¤¦▒', skill: 'mason' },
    { id: 'plumber', label: 'Plumbers', icon: '­¤Ü░', skill: 'plumber' },
    { id: 'carpenter', label: 'Carpenters', icon: '­¤¬Ü', skill: 'carpenter' },
    { id: 'welder', label: 'Welders', icon: '­¤öź', skill: 'welder' },
    { id: 'cleaner', label: 'Cleaners', icon: '­¤¦╣', skill: 'cleaner' },
    { id: 'gardener', label: 'Gardeners', icon: '­¤ī▒', skill: 'gardener' },
    { id: 'loader', label: 'Loaders', icon: '­¤ō”', skill: 'loader' },
    { id: 'tiler', label: 'Tilers', icon: '­¤ōÉ', skill: 'tiler' }
  ];

  useEffect(() => {
    fetchWorkers();
  }, [filter, city]);

  const fetchWorkers = async () => {
    try {
      const skillParam = filter !== 'all' ? categories.find(c => c.id === filter)?.skill : '';
      const query = [];
      if (skillParam) query.push(`skills=${skillParam}`);
      if (city) query.push(`city=${city}`);
      
      const response = await api.get(`/workers/search?${query.join('&')}`);
      setWorkers(response.data.workers);
    } catch (error) {
      console.error('Error fetching workers:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div className="loading">Loading workers...</div>;

  return (
    <div className="browse-container">
      <header className="browse-header">
        <h1>Find Skilled Workers</h1>
        <p>Browse experienced workers by service type and location</p>
      </header>

      <div className="filter-controls">
        <div className="category-filters">
          {categories.map(cat => (
            <button
              key={cat.id}
              className={`cat-filter-btn ${filter === cat.id ? 'active' : ''}`}
              onClick={() => setFilter(cat.id)}
            >
              {cat.icon && <span>{cat.icon}</span>} {cat.label}
            </button>
          ))}
        </div>
        <input
          type="text"
          placeholder="Filter by city..."
          className="city-search"
          value={city}
          onChange={(e) => setCity(e.target.value)}
        />
      </div>

      <div className="workers-grid">
        {workers.length > 0 ? (
          workers.map(worker => (
            <div key={worker._id} className="worker-profile-card">
              <div className="worker-photo">
                {worker.profileImage ? (
                  <img src={worker.profileImage} alt={worker.name} />
                ) : (
                  <div className="default-avatar">{worker.name.charAt(0)}</div>
                )}
              </div>
              <div className="worker-info-section">
                <h3>{worker.name}</h3>
                <div className="rating-bar">
                  <span className="stars">ŌŁÉ {worker.rating?.average || 0}</span>
                  <span className="reviews">({worker.rating?.count || 0} reviews)</span>
                </div>
                <div className="worker-skills">
                  {worker.skills?.map(skill => (
                    <span key={skill} className="skill-badge">{skill}</span>
                  ))}
                </div>
                <div className="worker-meta">
                  <p>­¤ōŹ {worker.location?.city}, {worker.location?.district}</p>
                  <p>­¤Æ╝ {worker.completedJobs || 0} jobs completed</p>
                  <p>ŌÅ▒’ĖÅ {worker.experience?.years || 0} years experience</p>
                  <p className="expert-tag">{worker.expertLevel}</p>
                </div>
                <button
                  className="contact-worker-btn"
                  onClick={() => navigate('/post-job')}
                >
                  Hire for a Job
                </button>
              </div>
            </div>
          ))
        ) : (
          <p className="no-results">No workers found. Try adjusting your filters.</p>
        )}
      </div>
    </div>
  );
};

export default BrowseWorkers;
